export enum UserRole {
  ADMIN = 'ADMIN',
  TEACHER = 'TEACHER'
}

export interface School {
  id: string;
  name: string;
  timezone: string;
  locale: string;
}

export interface User {
  id: string;
  email: string;
  name: string;
  password?: string; // Only used for mock auth check
  role: UserRole;
  school_id: string;
}

export interface Student {
  id: string;
  name: string;
  school_id: string;
  enrollment_date: string;
}

export interface Class {
  id: string;
  name: string;
  school_id: string;
  teacher_id?: string; // Assigned teacher
}

export interface Enrollment {
  student_id: string;
  class_id: string;
  school_id: string;
}

export type AttendanceStatus = 'present' | 'absent' | 'late';

export interface Attendance {
  id: string;
  student_id: string;
  class_id: string;
  school_id: string;
  date: string; // ISO Date string YYYY-MM-DD
  status: AttendanceStatus;
}

export interface DashboardStats {
  totalStudents: number;
  totalTeachers: number;
  totalClasses: number;
  attendancePercentageToday: number;
}

import { School, User, Student, Class, Enrollment, Attendance, UserRole } from '../types';

// Seed Data
const SCHOOL_ID = 'school-1';

const INITIAL_SCHOOL: School = {
  id: SCHOOL_ID,
  name: 'Springfield Elementary',
  timezone: 'UTC',
  locale: 'en-US'
};

const INITIAL_USERS: User[] = [
  { id: 'u1', email: 'admin@school.com', name: 'Principal Skinner', password: 'admin', role: UserRole.ADMIN, school_id: SCHOOL_ID },
  { id: 'u2', email: 'teacher@school.com', name: 'Edna Krabappel', password: 'teacher', role: UserRole.TEACHER, school_id: SCHOOL_ID },
  { id: 'u3', email: 'teacher2@school.com', name: 'Dewey Largo', password: 'teacher', role: UserRole.TEACHER, school_id: SCHOOL_ID },
];

const INITIAL_CLASSES: Class[] = [
  { id: 'c1', name: 'Grade 4 - Math', school_id: SCHOOL_ID, teacher_id: 'u2' },
  { id: 'c2', name: 'Grade 5 - History', school_id: SCHOOL_ID, teacher_id: 'u3' },
];

const INITIAL_STUDENTS: Student[] = [
  { id: 's1', name: 'Bart Simpson', school_id: SCHOOL_ID, enrollment_date: '2023-09-01' },
  { id: 's2', name: 'Lisa Simpson', school_id: SCHOOL_ID, enrollment_date: '2023-09-01' },
  { id: 's3', name: 'Milhouse Van Houten', school_id: SCHOOL_ID, enrollment_date: '2023-09-01' },
  { id: 's4', name: 'Ralph Wiggum', school_id: SCHOOL_ID, enrollment_date: '2023-09-01' },
  { id: 's5', name: 'Nelson Muntz', school_id: SCHOOL_ID, enrollment_date: '2023-09-01' },
];

const INITIAL_ENROLLMENTS: Enrollment[] = [
  { student_id: 's1', class_id: 'c1', school_id: SCHOOL_ID },
  { student_id: 's2', class_id: 'c1', school_id: SCHOOL_ID },
  { student_id: 's3', class_id: 'c1', school_id: SCHOOL_ID },
  { student_id: 's4', class_id: 'c1', school_id: SCHOOL_ID },
  { student_id: 's5', class_id: 'c1', school_id: SCHOOL_ID },
];

const INITIAL_ATTENDANCE: Attendance[] = []; // Starts empty

// Storage Keys
const KEYS = {
  USERS: 'erp_users',
  STUDENTS: 'erp_students',
  CLASSES: 'erp_classes',
  ENROLLMENTS: 'erp_enrollments',
  ATTENDANCE: 'erp_attendance',
  INIT: 'erp_initialized'
};

// Helper to simulate DB delay
const delay = (ms: number) => new Promise(res => setTimeout(res, ms));

export const db = {
  init: () => {
    if (!localStorage.getItem(KEYS.INIT)) {
      localStorage.setItem(KEYS.USERS, JSON.stringify(INITIAL_USERS));
      localStorage.setItem(KEYS.STUDENTS, JSON.stringify(INITIAL_STUDENTS));
      localStorage.setItem(KEYS.CLASSES, JSON.stringify(INITIAL_CLASSES));
      localStorage.setItem(KEYS.ENROLLMENTS, JSON.stringify(INITIAL_ENROLLMENTS));
      localStorage.setItem(KEYS.ATTENDANCE, JSON.stringify(INITIAL_ATTENDANCE));
      localStorage.setItem(KEYS.INIT, 'true');
    }
  },

  getUsers: (): User[] => JSON.parse(localStorage.getItem(KEYS.USERS) || '[]'),

  getStudents: (): Student[] => JSON.parse(localStorage.getItem(KEYS.STUDENTS) || '[]'),
  addStudent: (student: Student) => {
    const students = db.getStudents();
    students.push(student);
    localStorage.setItem(KEYS.STUDENTS, JSON.stringify(students));
  },

  getClasses: (): Class[] => JSON.parse(localStorage.getItem(KEYS.CLASSES) || '[]'),
  addClass: (cls: Class) => {
    const classes = db.getClasses();
    classes.push(cls);
    localStorage.setItem(KEYS.CLASSES, JSON.stringify(classes));
  },

  getEnrollments: (): Enrollment[] => JSON.parse(localStorage.getItem(KEYS.ENROLLMENTS) || '[]'),
  enrollStudent: (enrollment: Enrollment) => {
    const enrollments = db.getEnrollments();
    enrollments.push(enrollment);
    localStorage.setItem(KEYS.ENROLLMENTS, JSON.stringify(enrollments));
  },

  getAttendance: (): Attendance[] => JSON.parse(localStorage.getItem(KEYS.ATTENDANCE) || '[]'),
  saveAttendanceRecord: (record: Attendance) => {
    let attendance = db.getAttendance();
    // Update if exists, else add
    const idx = attendance.findIndex(a => 
      a.student_id === record.student_id && 
      a.class_id === record.class_id && 
      a.date === record.date
    );

    if (idx >= 0) {
      attendance[idx] = record;
    } else {
      attendance.push(record);
    }
    localStorage.setItem(KEYS.ATTENDANCE, JSON.stringify(attendance));
  },

  // Helpers
  getStudentsByClass: (classId: string): Student[] => {
    const enrollments = db.getEnrollments().filter(e => e.class_id === classId);
    const students = db.getStudents();
    return students.filter(s => enrollments.some(e => e.student_id === s.id));
  }
};

// Initialize on load
db.init();

import React, { createContext, useContext, useState, useEffect } from 'react';
import { User, UserRole } from '../types';
import { db } from './storage';

interface AuthContextType {
  user: User | null;
  login: (email: string, password: string) => Promise<boolean>;
  logout: () => void;
  loading: boolean;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Check local storage for active session simulation
    const storedUserId = localStorage.getItem('erp_session_user_id');
    if (storedUserId) {
      const users = db.getUsers();
      const found = users.find(u => u.id === storedUserId);
      if (found) setUser(found);
    }
    setLoading(false);
  }, []);

  const login = async (email: string, password: string): Promise<boolean> => {
    // Simulate API Call
    await new Promise(res => setTimeout(res, 500));

    const users = db.getUsers();
    const found = users.find(u => u.email === email && u.password === password);

    if (found) {
      setUser(found);
      localStorage.setItem('erp_session_user_id', found.id);
      return true;
    }
    return false;
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('erp_session_user_id');
  };

  return (
    <AuthContext.Provider value={{ user, login, logout, loading }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) throw new Error("useAuth must be used within AuthProvider");
  return context;
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'danger' | 'ghost';
  size?: 'sm' | 'md' | 'lg';
  loading?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  size = 'md', 
  loading,
  className = '',
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center rounded-md font-medium transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed";

  const variants = {
    primary: "bg-indigo-600 text-white hover:bg-indigo-700 focus:ring-indigo-500",
    secondary: "bg-white text-gray-700 border border-gray-300 hover:bg-gray-50 focus:ring-indigo-500",
    danger: "bg-red-600 text-white hover:bg-red-700 focus:ring-red-500",
    ghost: "text-gray-600 hover:bg-gray-100 hover:text-gray-900"
  };

  const sizes = {
    sm: "px-3 py-1.5 text-xs",
    md: "px-4 py-2 text-sm",
    lg: "px-6 py-3 text-base"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${sizes[size]} ${className}`}
      disabled={loading || props.disabled}
      {...props}
    >
      {loading ? (
        <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-current" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
          <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
          <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
        </svg>
      ) : null}
      {children}
    </button>
  );
};

