import React, { useState, useEffect } from 'react';
import { db } from '../lib/storage';
import { Class, User, UserRole, Student } from '../types';
import { Button } from '../components/ui/Button';
import { Plus, ChevronRight } from 'lucide-react';

export const Classes: React.FC = () => {
  const [classes, setClasses] = useState<Class[]>([]);
  const [teachers, setTeachers] = useState<User[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isAssignModalOpen, setIsAssignModalOpen] = useState(false);

  const [newClassName, setNewClassName] = useState('');
  const [selectedTeacherId, setSelectedTeacherId] = useState('');

  const [selectedClassIdForAssign, setSelectedClassIdForAssign] = useState<string | null>(null);
  const [selectedStudentToAssign, setSelectedStudentToAssign] = useState<string>('');

  useEffect(() => {
    refreshData();
  }, []);

  const refreshData = () => {
    setClasses(db.getClasses());
    setTeachers(db.getUsers().filter(u => u.role === UserRole.TEACHER));
    setStudents(db.getStudents());
  };

  const handleAddClass = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newClassName.trim()) return;

    const newClass: Class = {
      id: `c${Date.now()}`,
      name: newClassName,
      school_id: 'school-1',
      teacher_id: selectedTeacherId || undefined
    };

    db.addClass(newClass);
    refreshData();
    setNewClassName('');
    setSelectedTeacherId('');
    setIsModalOpen(false);
  };

  const handleAssignStudent = () => {
    if (!selectedClassIdForAssign || !selectedStudentToAssign) return;

    // Check if already enrolled
    const enrollments = db.getEnrollments();
    const exists = enrollments.find(e => e.class_id === selectedClassIdForAssign && e.student_id === selectedStudentToAssign);

    if (!exists) {
      db.enrollStudent({
        student_id: selectedStudentToAssign,
        class_id: selectedClassIdForAssign,
        school_id: 'school-1'
      });
      alert('Student assigned successfully!');
    } else {
      alert('Student is already assigned to this class.');
    }

    setIsAssignModalOpen(false);
  };

  const openAssignModal = (classId: string) => {
    setSelectedClassIdForAssign(classId);
    setSelectedStudentToAssign(students[0]?.id || '');
    setIsAssignModalOpen(true);
  };

  return (
    <div>
      <div className="md:flex md:items-center md:justify-between mb-6">
        <div className="flex-1 min-w-0">
          <h2 className="text-2xl font-bold leading-7 text-gray-900 sm:text-3xl sm:truncate">Classes</h2>
        </div>
        <div className="mt-4 flex md:mt-0 md:ml-4">
          <Button onClick={() => setIsModalOpen(true)}>
            <Plus className="w-4 h-4 mr-2" />
            Create Class
          </Button>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3">
        {classes.map((cls) => {
          const teacherName = teachers.find(t => t.id === cls.teacher_id)?.name || 'Unassigned';
          const studentCount = db.getEnrollments().filter(e => e.class_id === cls.id).length;

          return (
            <div key={cls.id} className="bg-white overflow-hidden shadow rounded-lg hover:shadow-md transition-shadow">
              <div className="px-4 py-5 sm:p-6">
                <div className="flex items-center justify-between">
                   <h3 className="text-lg leading-6 font-medium text-gray-900">{cls.name}</h3>
                   <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-800">
                     {studentCount} Students
                   </span>
                </div>
                <div className="mt-2 text-sm text-gray-500">
                  <p>Teacher: <span className="font-medium text-gray-700">{teacherName}</span></p>
                </div>
                <div className="mt-4">
                  <Button variant="secondary" size="sm" onClick={() => openAssignModal(cls.id)} className="w-full">
                    Assign Student
                  </Button>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Create Class Modal */}
      {isModalOpen && (
        <div className="fixed z-50 inset-0 flex items-center justify-center">
          <div className="absolute inset-0 bg-gray-500 opacity-75" onClick={() => setIsModalOpen(false)}></div>
          <div className="bg-white rounded-lg p-6 z-10 w-full max-w-md">
            <h3 className="text-lg font-medium mb-4">Create New Class</h3>
            <input
              className="w-full border rounded-md p-2 mb-3"
              placeholder="Class Name (e.g., Grade 10 Math)"
              value={newClassName}
              onChange={e => setNewClassName(e.target.value)}
            />
            <select
              className="w-full border rounded-md p-2 mb-4"
              value={selectedTeacherId}
              onChange={e => setSelectedTeacherId(e.target.value)}
            >
              <option value="">Select Teacher</option>
              {teachers.map(t => (
                <option key={t.id} value={t.id}>{t.name}</option>
              ))}
            </select>
            <div className="flex justify-end gap-2">
              <Button variant="secondary" onClick={() => setIsModalOpen(false)}>Cancel</Button>
              <Button onClick={handleAddClass}>Create</Button>
            </div>
          </div>
        </div>
      )}

      {/* Assign Student Modal */}
      {isAssignModalOpen && (
        <div className="fixed z-50 inset-0 flex items-center justify-center">
          <div className="absolute inset-0 bg-gray-500 opacity-75" onClick={() => setIsAssignModalOpen(false)}></div>
