export const db = {
  init: () => {
    if (!localStorage.getItem(KEYS.INIT)) {
      localStorage.setItem(KEYS.USERS, JSON.stringify(INITIAL_USERS));
      localStorage.setItem(KEYS.STUDENTS, JSON.stringify(INITIAL_STUDENTS));
      localStorage.setItem(KEYS.CLASSES, JSON.stringify(INITIAL_CLASSES));
      localStorage.setItem(KEYS.ENROLLMENTS, JSON.stringify(INITIAL_ENROLLMENTS));
      localStorage.setItem(KEYS.ATTENDANCE, JSON.stringify(INITIAL_ATTENDANCE));
      localStorage.setItem(KEYS.INIT, 'true');
    }
  },

  getUsers: (): User[] => JSON.parse(localStorage.getItem(KEYS.USERS) || '[]'),

  getStudents: (): Student[] => JSON.parse(localStorage.getItem(KEYS.STUDENTS) || '[]'),
  addStudent: (student: Student) => {
    const students = db.getStudents();
    students.push(student);
    localStorage.setItem(KEYS.STUDENTS, JSON.stringify(students));
  },

  getClasses: (): Class[] => JSON.parse(localStorage.getItem(KEYS.CLASSES) || '[]'),
  addClass: (cls: Class) => {
    const classes = db.getClasses();
    classes.push(cls);
    localStorage.setItem(KEYS.CLASSES, JSON.stringify(classes));
  },

  getEnrollments: (): Enrollment[] => JSON.parse(localStorage.getItem(KEYS.ENROLLMENTS) || '[]'),
  enrollStudent: (enrollment: Enrollment) => {
    const enrollments = db.getEnrollments();
    enrollments.push(enrollment);
    localStorage.setItem(KEYS.ENROLLMENTS, JSON.stringify(enrollments));
  },

  getAttendance: (): Attendance[] => JSON.parse(localStorage.getItem(KEYS.ATTENDANCE) || '[]'),
  saveAttendanceRecord: (record: Attendance) => {
    let attendance = db.getAttendance();
    const idx = attendance.findIndex(a => 
      a.student_id === record.student_id && 
      a.class_id === record.class_id && 
      a.date === record.date
    );

    if (idx >= 0) {
      attendance[idx] = record;
    } else {
      attendance.push(record);
    }
    localStorage.setItem(KEYS.ATTENDANCE, JSON.stringify(attendance));
  },

  getStudentsByClass: (classId: string): Student[] => {
    const enrollments = db.getEnrollments().filter(e => e.class_id === classId);
    const students = db.getStudents();
    return students.filter(s => enrollments.some(e => e.student_id === s.id));
  }
};

db.init();

