                  <p>Teacher: <span className="font-medium text-gray-700">{teacherName}</span></p>
                </div>
                <div className="mt-4">
                  <Button variant="secondary" size="sm" onClick={() => openAssignModal(cls.id)} className="w-full">
                    Assign Student
                  </Button>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* Create Class Modal */}
      {isModalOpen && (
        <div className="fixed z-50 inset-0 flex items-center justify-center">
          <div className="absolute inset-0 bg-gray-500 opacity-75" onClick={() => setIsModalOpen(false)}></div>
          <div className="bg-white rounded-lg p-6 z-10 w-full max-w-md">
            <h3 className="text-lg font-medium mb-4">Create New Class</h3>
