import React, { useState, useEffect } from 'react';
import { db } from '../lib/storage';
import { useAuth } from '../lib/auth';
import { Class, Student, Attendance as AttendanceType, UserRole, AttendanceStatus } from '../types';
import { Button } from '../components/ui/Button';
import { Check, X, Calendar } from 'lucide-react';

export const Attendance: React.FC = () => {
  const { user } = useAuth();
  const [classes, setClasses] = useState<Class[]>([]);
  const [selectedClass, setSelectedClass] = useState<string>('');
  const [students, setStudents] = useState<Student[]>([]);
  const [attendanceDate, setAttendanceDate] = useState(new Date().toISOString().split('T')[0]);
  const [attendanceState, setAttendanceState] = useState<Record<string, AttendanceStatus>>({});
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    // Load classes based on role
    const allClasses = db.getClasses();
    if (user?.role === UserRole.TEACHER) {
      const teacherClasses = allClasses.filter(c => c.teacher_id === user.id);
      setClasses(teacherClasses);
      if (teacherClasses.length > 0) setSelectedClass(teacherClasses[0].id);
    } else {
      setClasses(allClasses);
      if (allClasses.length > 0) setSelectedClass(allClasses[0].id);
    }
  }, [user]);

  useEffect(() => {
    if (selectedClass) {
      const classStudents = db.getStudentsByClass(selectedClass);
      setStudents(classStudents);

      // Load existing attendance for this date
      const existing = db.getAttendance().filter(a => a.class_id === selectedClass && a.date === attendanceDate);
      const state: Record<string, AttendanceStatus> = {};

      classStudents.forEach(s => {
        const record = existing.find(e => e.student_id === s.id);
        state[s.id] = (record ? record.status : 'PRESENT') as AttendanceStatus; // Default to present
      });
      setAttendanceState(state);
    }
  }, [selectedClass, attendanceDate]);

  const handleStatusChange = (studentId: string, status: AttendanceStatus) => {
    setAttendanceState(prev => ({ ...prev, [studentId]: status }));
  };

  const saveAttendance = async () => {
    setLoading(true);
    // Simulate API delay
    await new Promise(res => setTimeout(res, 600));

    Object.entries(attendanceState).forEach(([studentId, status]) => {
      const record: AttendanceType = {
        id: `${studentId}-${attendanceDate}`,
        student_id: studentId,
        class_id: selectedClass,
        school_id: user?.school_id || 'school-1',
        date: attendanceDate,
        status: status,
        marked_by: user?.id || 'system'
      };
      db.saveAttendanceRecord(record);
    });

    setLoading(false);
    alert('Attendance saved successfully!');
  };

  if (classes.length === 0) {
    return (
      <div className="text-center py-10">
        <h3 className="text-lg font-medium text-gray-900">No classes assigned</h3>
        <p className="mt-1 text-sm text-gray-500">You need to be assigned to a class to mark attendance.</p>
      </div>
    );
  }

  return (
    <div>
      <div className="md:flex md:items-center md:justify-between mb-6">
        <h2 className="text-2xl font-bold leading-7 text-gray-900 sm:text-3xl">Mark Attendance</h2>
        <div className="mt-4 md:mt-0 flex space-x-3">
          <input 
            type="date" 
            className="border rounded-md px-3 py-2 text-sm"
            value={attendanceDate}
            onChange={(e) => setAttendanceDate(e.target.value)}
          />
          <Button onClick={saveAttendance} loading={loading}>
            Save Attendance
          </Button>
        </div>
      </div>

      <div className="bg-white shadow rounded-lg mb-6 p-4">
        <label className="block text-sm font-medium text-gray-700 mb-2">Select Class</label>
        <select 
          className="block w-full pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-indigo-500 focus:border-indigo-500 sm:text-sm rounded-md"
          value={selectedClass}
          onChange={(e) => setSelectedClass(e.target.value)}
        >
          {classes.map(c => (
            <option key={c.id} value={c.id}>{c.name} - {c.section}</option>
          ))}
        </select>
      </div>

      <div className="bg-white shadow overflow-hidden sm:rounded-md">
        <ul className="divide-y divide-gray-200">
          {students.map((student) => (
            <li key={student.id} className="px-4 py-4 sm:px-6 hover:bg-gray-50 flex items-center justify-between">
              <div className="flex items-center">
                <div className="flex-shrink-0 h-10 w-10 rounded-full bg-gray-200 flex items-center justify-center text-gray-500 font-bold">
                  {student.first_name.charAt(0)}
                </div>
                <div className="ml-4">
                  <div className="text-sm font-medium text-indigo-600">{student.first_name} {student.last_name}</div>
                  <div className="text-sm text-gray-500">ID: {student.enrollment_number}</div>
                </div>
              </div>

              <div className="flex space-x-2">
                <button
                  onClick={() => handleStatusChange(student.id, 'PRESENT')}
                  className={`inline-flex items-center px-3 py-1.5 border text-xs font-medium rounded-full ${
                    attendanceState[student.id] === 'PRESENT' 
                      ? 'bg-green-100 text-green-800 border-green-200' 
                      : 'bg-white text-gray-500 border-gray-300 hover:bg-gray-50'
                  }`}
                >
                  <Check className="w-3 h-3 mr-1" /> Present
                </button>
                <button
                  onClick={() => handleStatusChange(student.id, 'ABSENT')}
                  className={`inline-flex items-center px-3 py-1.5 border text-xs font-medium rounded-full ${
                    attendanceState[student.id] === 'ABSENT' 
                      ? 'bg-red-100 text-red-800 border-red-200' 
                      : 'bg-white text-gray-500 border-gray-300 hover:bg-gray-50'
                  }`}
                >
                  <X className="w-3 h-3 mr-1" /> Absent
                </button>
              </div>
            </li>
          ))}
          {students.length === 0 && (
            <li className="px-4 py-8 text-center text-gray-500">
              No students enrolled in this class yet.
            </li>
          )}
        </ul>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
