    const todaysRecords = attendance.filter(a => a.date === today);
    const presentCount = todaysRecords.filter(a => a.status === 'PRESENT').length;
    // Rough estimate: total expected is roughly enrollments count, but for simplicity let's use current records as denominator if > 0
    const attendanceRate = todaysRecords.length > 0 
      ? Math.round((presentCount / todaysRecords.length) * 100) 
      : 0;

    setStats({
      students: students.length,
      teachers: teachers.length,
      classes: classes.length,
      attendanceRate
    });

    // Mock Chart Data for "Last 5 Days Attendance"
    const data = [
      { name: 'Mon', present: 85 },
      { name: 'Tue', present: 88 },
      { name: 'Wed', present: 92 },
      { name: 'Thu', present: 90 },
      { name: 'Fri', present: attendanceRate || 95 }, // Use current if avail, else mock
    ];
    setChartData(data);

  }, []);

  const StatCard = ({ title, value, icon: Icon, color }: any) => (
    <div className="bg-white overflow-hidden shadow rounded-lg">
      <div className="p-5">
        <div className="flex items-center">
          <div className={`flex-shrink-0 p-3 rounded-md ${color}`}>
            <Icon className="h-6 w-6 text-white" />
          </div>
          <div className="ml-5 w-0 flex-1">
            <dl>
              <dt className="text-sm font-medium text-gray-500 truncate">{title}</dt>
              <dd className="text-3xl font-semibold text-gray-900">{value}</dd>
            </dl>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div>
      <h1 className="text-2xl font-semibold text-gray-900 mb-6">
        {user?.role === UserRole.ADMIN ? 'Admin Dashboard' : `Welcome, ${user?.name}`}
      </h1>

      <div className="grid grid-cols-1 gap-5 sm:grid-cols-2 lg:grid-cols-4 mb-8">
        <StatCard 
          title="Total Students" 
          value={stats.students} 
          icon={Users} 
          color="bg-indigo-500" 
        />
        {user?.role === UserRole.ADMIN && (
          <StatCard 
            title="Total Teachers" 
            value={stats.teachers} 
            icon={UserCheck} 
            color="bg-green-500" 
          />
        )}
        <StatCard 
          title="Active Classes" 
          value={stats.classes} 
          icon={BookOpen} 
          color="bg-orange-500" 
        />
        <StatCard 
          title="Attendance Today" 
          value={`${stats.attendanceRate}%`} 
          icon={Activity} 
          color="bg-blue-500" 
        />
      </div>

      <div className="bg-white shadow rounded-lg p-6">
        <h3 className="text-lg leading-6 font-medium text-gray-900 mb-4">Weekly Attendance Overview</h3>
        <div className="h-80 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="name" />
              <YAxis />
              <Tooltip />
              <Bar dataKey="present" name="Attendance %" fill="#4f46e5" radius={[4, 4, 0, 0]}>
                {chartData.map((entry, index) => (
                   <Cell key={`cell-${index}`} fill={entry.present < 90 ? '#ef4444' : '#4f46e5'} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* AI Readiness Placeholder */}
      <div className="mt-8 bg-gradient-to-r from-indigo-50 to-blue-50 border border-indigo-100 rounded-lg p-6">
        <div className="flex items-start">
          <div className="flex-shrink-0">
            <Activity className="h-6 w-6 text-indigo-600" />
          </div>
          <div className="ml-4">
            <h3 className="text-lg font-medium text-indigo-900">AI Insights (Coming Soon)</h3>
            <p className="mt-1 text-sm text-indigo-700">
              The platform is ready for AI integration. Future updates will include predictive attendance analysis and student performance insights powered by Gemini.
            </p>
          </div>
        </div>
      </div>

    </div>
  );
};

