payload.text:
Core rules for Step 2

All APIs are school-scoped

User only sees their own school’s data

Role-based access (Admin vs Teacher)

Stateless (JWT-ready)

2.1 Install & configure DRF

pip install djangorestframework
# settings.py
INSTALLED_APPS = [
    ...
    'rest_framework',
]
REST_FRAMEWORK = {
    "DEFAULT_AUTHENTICATION_CLASSES": (
        "rest_framework.authentication.SessionAuthentication",
    ),
    "DEFAULT_PERMISSION_CLASSES": (
        "rest_framework.permissions.IsAuthenticated",
    ),
}

2.2 Serializers

School serializer

from rest_framework import serializers
from .models import School

class SchoolSerializer(serializers.ModelSerializer):
    class Meta:
        model = School
        fields = ["id", "name", "code", "timezone", "locale"]

User serializer

from .models import User

class UserSerializer(serializers.ModelSerializer):
    class Meta:
        model = User
        fields = ["id", "email", "role"]

Student serializer (school enforced)

from .models import Student

class StudentSerializer(serializers.ModelSerializer):
    class Meta:
        model = Student
        fields = ["id", "first_name", "last_name", "enrollment_number"]

    def create(self, validated_data):
        validated_data["school"] = self.context["request"].user.school
        return super().create(validated_data)


Class serializer

from .models import Class

class ClassSerializer(serializers.ModelSerializer):
    class Meta:
        model = Class
        fields = ["id", "name", "section", "class_teacher"]

    def create(self, validated_data):
        validated_data["school"] = self.context["request"].user.school
        return super().create(validated_data)


Attendance serializer

from .models import Attendance

class AttendanceSerializer(serializers.ModelSerializer):
    class Meta:
        model = Attendance
        fields = ["id", "student", "class_obj", "date", "status"]

    def create(self, validated_data):
        validated_data["marked_by"] = self.context["request"].user
        return super().create(validated_data)


2.3 Permissions (VERY IMPORTANT)

Role-based permission

from rest_framework.permissions import BasePermission

class IsAdmin(BasePermission):
    def has_permission(self, request, view):
        return request.user.role == "ADMIN"


class IsTeacher(BasePermission):
    def has_permission(self, request, view):
        return request.user.role == "TEACHER"


2.4 ViewSets (School-safe)

Students API

from rest_framework.viewsets import ModelViewSet
from .models import Student
from .serializers import StudentSerializer

class StudentViewSet(ModelViewSet):
    serializer_class = StudentSerializer

    def get_queryset(self):
        return Student.objects.filter(
            school=self.request.user.school
        )


Classes API

from .models import Class
from .serializers import ClassSerializer

class ClassViewSet(ModelViewSet):
    serializer_class = ClassSerializer

    def get_queryset(self):
        return Class.objects.filter(
            school=self.request.user.school
        )


Attendance API (teacher-only)

from rest_framework.permissions import IsAuthenticated
from .permissions import IsTeacher

class AttendanceViewSet(ModelViewSet):
    serializer_class = AttendanceSerializer
    permission_classes = [IsAuthenticated, IsTeacher]

    def get_queryset(self):
        return Attendance.objects.filter(
            class_obj__school=self.request.user.school
        )


2.5 Dashboard API (custom)

from rest_framework.views import APIView
from rest_framework.response import Response

class DashboardView(APIView):

    def get(self, request):
        school = request.user.school

        data = {
            "students": school.students.count(),
            "teachers": school.users.filter(role="TEACHER").count(),
            "classes": school.classes.count(),
        }
        return Response(data)

2.6 URL Routing

from rest_framework.routers import DefaultRouter
from .views import StudentViewSet, ClassViewSet, AttendanceViewSet

router = DefaultRouter()
router.register("students", StudentViewSet, basename="students")
router.register("classes", ClassViewSet, basename="classes")
router.register("attendance", AttendanceViewSet, basename="attendance")

urlpatterns = router.urls

