  id: string;
  name: string;
  code: string;
  timezone: string;
  locale: string;
  is_active: boolean;
}

export interface User {
  id: string;
  email: string;
  name: string; // UI convenience, mostly derived or separate profile
  password?: string;
  role: UserRole;
  school_id: string; // Needed internally for auth context
}

export interface AuthResponse {
  access: string;
  refresh: string;
}

export interface Student {
  id: string;
  first_name: string;
  last_name: string;
  enrollment_number: string;
  // school_id is implicit in API scope
}

export interface Class {
  id: string;
  name: string;
  section: string;
  class_teacher?: string; // ID of the teacher
  // school_id is implicit in API scope
}

export interface Enrollment {
  student: string; // ID
  class_obj: string; // ID (ForeignKey to Class)
  academic_year: string;
}

export type AttendanceStatus = 'PRESENT' | 'ABSENT';

export interface Attendance {
  id: string;
  student: string; // ID
  class_obj: string; // ID
  date: string; // YYYY-MM-DD
  status: AttendanceStatus;
  // marked_by is not in the read serializer fields
}

export interface DashboardStats {
  students: number;
  teachers: number;
  classes: number;
}

import { School, User, Student, Class, Enrollment, Attendance, UserRole, DashboardStats, AuthResponse } from '../types';

// Mock Database State (Internal)
// We keep school_id here to simulate the Relational DB, even if APIs don't return it
interface DBStudent extends Student { school_id: string; created_at: string; is_active: boolean; }
interface DBClass extends Class { school_id: string; }
interface DBEnrollment extends Enrollment { school_id: string; }
interface DBAttendance extends Attendance { school_id: string; marked_by: string; }

