  id: string;
  name: string;
  code: string;
  timezone: string;
  locale: string;
  is_active: boolean;
}

export interface User {
  id: string;
  email: string;
  name: string; // UI convenience, mostly derived or separate profile
  password?: string;
  role: UserRole;
  school_id: string; // Needed internally for auth context
  school_name?: string; // For UI display
}

