class ParentDashboardView(APIView):
    permission_classes = [IsAuthenticated]

    def get(self, request):
        if request.user.role != "PARENT":
            return Response({"detail": "Unauthorized"}, status=403)

        student = request.user.student
        data = {
            "student_name": f"{student.first_name} {student.last_name}",
            "attendance": list(
                student.attendance_set.values("date", "status")
            ),
            "classes": list(
                student.enrollment_set.values("class_obj__name")
            ),
        }
        return Response(data)


6.3 Communication Layer — Design Principles

We separate concerns:

Message templates (prompt logic ready)

Delivery channels (Email / WhatsApp / SMS)

Scheduling / event triggers (attendance, fee due, announcement)

6.3.1 Email

Use SMTP / transactional email service (SendGrid, Amazon SES)

Example template: Attendance alert

from django.core.mail import send_mail

def send_attendance_email(student, parent_email):
    subject = f"Attendance Alert: {student.first_name}"
    message = f"Dear Parent, your child {student.first_name} was absent today."
    send_mail(subject, message, "no-reply@schoolerp.com", [parent_email])


6.3.2 WhatsApp (Meta Cloud API)

Requires WhatsApp Business Cloud API

Trigger messages via a background task (Celery / Django-Q)

Example pseudo-code:

import requests

def send_whatsapp_message(parent_number, message):
    url = "https://graph.facebook.com/v16.0/<PHONE_NUMBER_ID>/messages"
    headers = {"Authorization": "Bearer <ACCESS_TOKEN>"}
    data = {
        "messaging_product": "whatsapp",
        "to": parent_number,
        "text": {"body": message},
    }
    response = requests.post(url, headers=headers, json=data)
    return response.json()


6.3.3 Event-based triggers

Attendance → trigger email/WhatsApp if absent

Exam results → trigger automated notifications

Fee reminders → trigger scheduled messages

# Example: Attendance trigger
def attendance_marked(attendance_obj):
    student = attendance_obj.student
    for parent in student.parents.all():
        message = f"{student.first_name} was marked {attendance_obj.status} today."
        send_email(student, parent.email, message)
        send_whatsapp_message(parent.phone_number, message)


