      <div className="grid grid-cols-1 gap-6 sm:grid-cols-2 lg:grid-cols-3">
        {classes.map((cls) => {
          const teacherName = teachers.find(t => t.id === cls.class_teacher)?.name || 'Unassigned';

          return (
            <div key={cls.id} className="bg-white overflow-hidden shadow rounded-lg hover:shadow-md transition-shadow">
              <div className="px-4 py-5 sm:p-6">
                <div className="flex items-center justify-between">
                   <h3 className="text-lg leading-6 font-medium text-gray-900">{cls.name} <span className="text-gray-500 text-sm">({cls.section})</span></h3>
                </div>
                <div className="mt-2 text-sm text-gray-500 mb-4">
                  <p>Teacher: <span className="font-medium text-gray-700">{teacherName}</span></p>
                </div>

                <button 
                  onClick={() => handleViewAnalytics(cls)}
                  className="w-full flex items-center justify-center px-4 py-2 border border-purple-200 shadow-sm text-sm font-medium rounded-md text-purple-700 bg-purple-50 hover:bg-purple-100 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-purple-500"
                >
                  <Sparkles className="w-4 h-4 mr-2" />
                  AI Insights
                </button>
              </div>
            </div>
          );
        })}
      </div>

      {/* Create Class Modal */}
      {isModalOpen && (
        <div className="fixed z-50 inset-0 flex items-center justify-center">
          <div className="absolute inset-0 bg-gray-500 opacity-75" onClick={() => setIsModalOpen(false)}></div>
          <div className="bg-white rounded-lg p-6 z-10 w-full max-w-md">
            <h3 className="text-lg font-medium mb-4">Create New Class</h3>
            <form onSubmit={handleAddClass}>
              <input
                className="w-full border rounded-md p-2 mb-3"
                placeholder="Class Name (e.g., Grade 10)"
                value={formData.name}
                onChange={e => setFormData({...formData, name: e.target.value})}
                required
              />
              <input
                className="w-full border rounded-md p-2 mb-3"
                placeholder="Section (e.g., A)"
                value={formData.section}
                onChange={e => setFormData({...formData, section: e.target.value})}
                required
              />
              <select
                className="w-full border rounded-md p-2 mb-4"
                value={formData.teacherId}
                onChange={e => setFormData({...formData, teacherId: e.target.value})}
              >
                <option value="">Select Teacher</option>
                {teachers.map(t => (
                  <option key={t.id} value={t.id}>{t.name}</option>
                ))}
              </select>
              <div className="flex justify-end gap-2">
                <Button variant="secondary" type="button" onClick={() => setIsModalOpen(false)}>Cancel</Button>
                <Button type="submit">Create</Button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* AI Analytics Modal */}
      {analyticsClass && (
        <div className="fixed z-50 inset-0 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-gray-500 opacity-75" onClick={() => setAnalyticsClass(null)}></div>
          <div className="bg-white rounded-lg shadow-xl z-10 w-full max-w-lg overflow-hidden flex flex-col max-h-[90vh]">
            <div className="px-6 py-4 border-b border-gray-200 flex justify-between items-center bg-purple-50">
              <h3 className="text-lg font-bold text-purple-900 flex items-center">
                <Sparkles className="w-5 h-5 mr-2" />
                AI Insights: {analyticsClass.name}
              </h3>
              <button onClick={() => setAnalyticsClass(null)} className="text-gray-400 hover:text-gray-500">
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="p-6 overflow-y-auto">
              {loadingAi ? (
                <div className="flex flex-col items-center justify-center py-8 space-y-4">
                  <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-purple-600"></div>
                  <p className="text-sm text-gray-500">Analyzing attendance patterns...</p>
                </div>
              ) : (
                <div className="prose prose-purple prose-sm max-w-none whitespace-pre-line text-gray-700">
                  {aiSummary}
                </div>
              )}
            </div>

            <div className="px-6 py-4 bg-gray-50 border-t border-gray-200 flex justify-end">
              <Button variant="secondary" onClick={() => setAnalyticsClass(null)}>Close</Button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export enum UserRole {
  ADMIN = 'ADMIN',
  TEACHER = 'TEACHER',
  PARENT = 'PARENT'
}

export interface School {
  id: string;
  name: string;
  code: string;
  timezone: string;
  locale: string;
  is_active: boolean;
}

export interface User {
  id: string;
  email: string;
  name: string; // UI convenience, mostly derived or separate profile
  password?: string;
  role: UserRole;
  school_id: string; // Needed internally for auth context
  school_name?: string; // For UI display
  student_id?: string; // For PARENT role: links to their child
}

export interface AuthResponse {
  access: string;
  refresh: string;
}

export interface Student {
  id: string;
  first_name: string;
  last_name: string;
  enrollment_number: string;
  // school_id is implicit in API scope
}

export interface Class {
  id: string;
  name: string;
  section: string;
  class_teacher?: string; // ID of the teacher
  // school_id is implicit in API scope
}

export interface Enrollment {
  student: string; // ID
  class_obj: string; // ID (ForeignKey to Class)
  academic_year: string;
}

export type AttendanceStatus = 'PRESENT' | 'ABSENT';

export interface Attendance {
  id: string;
  student: string; // ID
  class_obj: string; // ID
  date: string; // YYYY-MM-DD
  status: AttendanceStatus;
  // marked_by is not in the read serializer fields
}

export interface DashboardStats {
  students: number;
  teachers: number;
  classes: number;
}

export interface ParentDashboardData {
  student_name: string;
  attendance: { date: string; status: AttendanceStatus }[];
  classes: string[];
}

// --- Finance Module Types ---

export interface FeeCategory {
  id: string;
  name: string;
  amount: number;
  description?: string;
  school_id: string;
}

export interface StudentFee {
  id: string;
  student_id: string;
  category_id: string; // Link to FeeCategory
  category_name?: string; // For UI convenience
  due_date: string;
  amount: number; // Snapshot of amount at time of assignment
  is_paid: boolean;
  paid_on?: string;
  school_id: string;
}

export interface Payment {
  id: string;
  fee_id: string;
  amount: number;
  date: string;
  method: string;
  transaction_id: string;
  status: 'SUCCESS' | 'FAILED' | 'PENDING';
  school_id: string;
}

// Simulates ai/prompt_templates.py and ai/generator.py

interface PromptContext {
  [key: string]: any;
}

const PROMPTS = {
  attendance_alert: (ctx: PromptContext) => 
    `Subject: Attendance Alert for ${ctx.student_name}\n\n` +
    `Dear Parent,\n\n` +
    `This is a polite message from ${ctx.school_name}. ` +
    `We noticed that ${ctx.student_name} was marked ${ctx.status} today (${ctx.date}). ` +
    `Please ensure they catch up on any missed work.\n\n` +
    `Regards,\n${ctx.school_name} Administration`,

  class_summary: (ctx: PromptContext) => 
    `### AI Analysis for ${ctx.class_name}\n\n` +
    `**Overview:**\n` +
    `The class has an average attendance of **${ctx.average_attendance}%** over the recorded period. ` +
    `Active student count: ${ctx.total_students}.\n\n` +
    `**Key Insights:**\n` +
    `- ${ctx.risk_count > 0 ? `⚠️ **Attention Needed:** ${ctx.risk_count} student(s) have falling attendance rates (<75%).` : `✅ **Great Job:** Most students are maintaining good attendance.`}\n` +
    `- ${ctx.average_attendance > 90 ? "Class engagement is high." : "Class engagement shows room for improvement."}\n\n` +
    `**AI Recommendations:**\n` +
    `1. ${ctx.risk_count > 0 ? "Schedule brief 1-on-1 check-ins with at-risk students." : "Continue current engagement strategies."}\n` +
    `2. ${ctx.average_attendance < 85 ? "Consider sending a positive reinforcement message to the whole class group." : "Plan a reward activity for consistent attendance."}\n` +
    `3. ${ctx.risk_count > 2 ? "Review the curriculum pace; multiple students falling behind might indicate content difficulty." : "Monitor the upcoming exam results to correlate with attendance patterns."}`,

  payment_receipt: (ctx: PromptContext) =>
    `Subject: Payment Receipt - ${ctx.transaction_id}\n\n` +
    `Dear Parent,\n\n` +
    `We have successfully received a payment of **$${ctx.amount}** for **${ctx.fee_name}** regarding student **${ctx.student_name}**.\n` +
    `Date: ${ctx.date}\n` +
    `Payment Method: ${ctx.method}\n\n` +
    `Thank you for your prompt payment.\n` +
    `Regards,\n${ctx.school_name} Finance Dept.`
};

export const ai = {
  /**
   * Simulates calling OpenAI to generate a message based on a template.
   */
  generateMessage: async (templateKey: keyof typeof PROMPTS, context: PromptContext): Promise<string> => {
    // Simulate network latency for AI processing
    await new Promise(res => setTimeout(res, 800));

    const template = PROMPTS[templateKey];
    if (!template) {
      throw new Error(`Prompt template '${templateKey}' not found.`);
    }

    // In a real app, 'context' would be passed to the LLM system prompt
    return template(context);
  },

  /**
   * Specific helper to analyze class data and return an "AI" insight
   */
  generateClassInsight: async (data: {
    className: string;
    totalStudents: number;
    averageAttendance: number;
    atRiskCount: number;
    schoolName: string;
  }) => {
    return ai.generateMessage('class_summary', {
      class_name: data.className,
      total_students: data.totalStudents,
      average_attendance: data.averageAttendance.toFixed(1),
      risk_count: data.atRiskCount,
      school_name: data.schoolName
    });
  }
};

