        <ul className="divide-y divide-gray-200">
          {fees.length > 0 ? fees.map((fee) => (
            <li key={fee.id} className="px-4 py-4 sm:px-6 hover:bg-gray-50">
              <div className="flex items-center justify-between">
                <div className="flex items-center">
                  <div className={`flex-shrink-0 h-10 w-10 rounded-full flex items-center justify-center ${
                    fee.is_paid ? 'bg-green-100 text-green-600' : 'bg-orange-100 text-orange-600'
                  }`}>
                    <DollarSign className="w-6 h-6" />
                  </div>
                  <div className="ml-4">
                    <div className="text-sm font-medium text-indigo-600">
                      {fee.category_name}
                    </div>
                    <div className="text-sm text-gray-500">
                      Due: {fee.due_date} {isAdmin && <span>| Student ID: {fee.student_id}</span>}
                    </div>
                  </div>
                </div>
                <div className="flex items-center">
                  <div className="mr-6 text-right">
                    <div className="text-sm font-bold text-gray-900">${fee.amount}</div>
                    <div className={`text-xs inline-flex items-center ${
                      fee.is_paid ? 'text-green-600' : 'text-orange-600'
                    }`}>
                      {fee.is_paid ? (
                        <><CheckCircle className="w-3 h-3 mr-1" /> Paid on {fee.paid_on}</>
                      ) : (
                        <><Clock className="w-3 h-3 mr-1" /> Pending</>
                      )}
                    </div>
                  </div>

                  {isParent && !fee.is_paid && (
                    <Button 
                      onClick={() => handlePay(fee.id)} 
                      loading={payingId === fee.id}
                      size="sm"
                    >
                      Pay Now
                    </Button>
                  )}
                </div>
              </div>
            </li>
          )) : (
            <li className="px-4 py-8 text-center text-gray-500">
              No fee records found.
            </li>
          )}
        </ul>
      </div>
    </div>
  );
};

